import photo from "../Files/discord server icon.gif"
import StarRatingByUser from "./Rating/StarRatingByUser";
import ShowText from "./ShowText";

function RatingCard({CommentText}) {

  return (
    <div className="rating-card">
      <div style={{display:"flex", justifyContent:"center", marginBottom:"1rem"}}>
        <img src={photo} width={60} height={60}/>
        <div style={{display:"flex", flexDirection:'column'}}>
          <span>Name</span>
          <StarRatingByUser rating={3.7}/>
        </div>
      </div>
      <ShowText text={CommentText}/>
    </div>
  );
}

export default RatingCard;
